let draft = $input.first().json.text || $input.first().json.output || $input.first().json;

function parseTables(text) {
    const tableRegex = /(?:^|\n)(\|[^\n]+\|(?:\n\|[^\n]+\|)+)/g;
    return text.replace(tableRegex, (match, tableBlock) => {
        let rows = tableBlock.trim().split('\n');
        let html = '<table style="border-collapse: collapse; width: 100%; margin: 20px 0; font-size: 14px; text-align: left;">\n';
        for (let i = 0; i < rows.length; i++) {
            let row = rows[i].trim();
            // check if it's the separator row e.g. |---|---|
            if (row.replace(/[\s|:\-]/g, '').length === 0) continue; 

            let cells = row.split('|');
            cells.shift(); // remove empty before first |
            cells.pop();   // remove empty after last |

            html += '  <tr>\n';
            for (let cell of cells) {
                let tag = i === 0 ? 'th' : 'td';
                let style = i === 0 
                  ? ' style="background-color: #f4f4f4; padding: 12px; border: 1px solid #ddd; border-bottom: 2px solid #bbb;"' 
                  : ' style="padding: 12px; border: 1px solid #ddd;"';
                html += `    <${tag}${style}>${cell.trim()}</${tag}>\n`;
            }
            html += '  </tr>\n';
        }
        html += '</table>\n';
        return '\n\n' + html + '\n\n';
    });
}

draft = parseTables(draft);

return [{
  json: { text: draft },
  binary: {
    data: {
      data: Buffer.from(draft).toString('base64'),
      mimeType: 'text/plain',
      fileName: 'temp_draft.txt'
    }
  }
}];

